        FastDateParser parser3= new FastDateParser('d', "20abc", "dd");
        System.out.println(parser3.parse().getDayOfMonth());

        FastDateParser parser4= new FastDateParser('d', "abcd", "dd");
        System.out.println(parser4.parse().getDayOfMonth());

        FastDateParser parser5= new FastDateParser('d', "", "dd");
        System.out.println(parser5.parse().getDayOfMonth());

        FastDateParser parser6= new FastDateParser('d', "0", "dd");
        System.out.println(parser6.parse().getDayOfMonth());

        FastDateParser parser7= new FastDateParser('M', "8", "MM");
        System.out.println(parser7.parse().getMonthOfYear());

        FastDateParser parser8= new FastDateParser('M', "09", "MM");
        System.out.println(parser8.parse().getMonthOfYear());

        FastDateParser parser9= new FastDateParser('y', "2010", "yyyy");
        System.out.println(parser9.parse().getYear());

        FastDateParser parser10= new FastDateParser('y', "9", "yyyy");
        System.out.println(parser10.parse().getYear());
    }

    private static class FastDateParser extends org.apache.commons.lang3.time.FastDateParser {
        public FastDateParser(char fieldId, String value, String... formats) throws ParseException {
            super((fieldId == 'y') ? Integer.valueOf(value).intValue() : Long.valueOf(value), TimeZone.getDefault(), Locale.US, formats);
        }

        @Override
        protected Object parseSpecial(FieldAwareDateTimeFormatter formatter) throws ParseException {
            int beginIndex= formatter.index();
            FormatUtil.ParseResult result= formatter.parseFrom(formatter.buffer(), beginIndex, 1);
            try {
                return getFieldBasedOnID(result.id()).parse(result.text());
            } catch (IllegalArgumentException ex) {
                throw new ParseException(formatter.buffer(), beginIndex);
            }
        }
    }
}

